		SELECT infra.mgr_no, infra.org_mgr_no, infra.site_mgr_no, infra.inst_dat, infra.fcl_gbn_cd,
               infra.ip_addr, infra.port_num, infra.use_yn, infra.con_id, infra.con_pwd, infra.snmp_str,
               infra.stat_chk_yn, infra.facility_id, infra.facility_nm, infra.facility_clscd, infra.loc_desc, infra.rmark

               , status.state_cd AS state_cd


               , sig.sig_kor_nm || ' ' || emd.emd_kor_nm || ' ' || li.li_kor_nm || ' ' || cbnd.jibun AS addr
               , cbnd.pnu
               , st_x(st_centroid(st_transform(infra._geometry, 4326))) AS lng
               , st_y(st_centroid(st_transform(infra._geometry, 4326))) AS lat

        FROM xeus.asset_infra AS infra
        LEFT JOIN xeus.asset_status AS status ON infra.mgr_no = status.mgr_no

        LEFT JOIN xeus.kras_cbnd_as AS cbnd ON st_intersects(cbnd._geometry, infra._geometry)
        LEFT JOIN xeus.kais_sig_as AS sig ON sig.sig_cd = substr(cbnd.pnu, 0, 6)
        LEFT JOIN xeus.kais_emd_as AS emd ON emd.emd_cd = substr(cbnd.pnu, 0, 9)
        LEFT JOIN xeus.kais_li_as AS li ON li.li_cd = substr(cbnd.pnu, 0, 11)





                st_intersects(emd._geometry, infra._geometry)

