                AND lower(infra.facility_clscd) like '%' || lower(#{facilityClscd}) || '%'



                AND infra.loc_desc = #{locDesc}



                AND infra.rmark = #{rmark}



                AND COALESCE(status.state_cd, null, 'null')  <>  #{stateCd}






				${sortCol} ${sortTyp}



