        LEFT JOIN xeus.kais_emd_as emd on emd.emd_cd = substr(cbnd.pnu, 0, 9)
        LEFT JOIN xeus.kais_li_as li on li.li_cd = substr(cbnd.pnu, 0, 11)




                st_intersects(emd._geometry, infra._geometry)

                AND emd.emd_cd = #{emdCd}



