mapper.insert:
INSERT INTO xeus.asset_infra( mgr_no, org_mgr_no, site_mgr_no, inst_dat, fcl_gbn_cd, ip_addr,
port_num,
use_yn, con_id, con_pwd, snmp_str, stat_chk_yn, facility_id, facility_nm, loc_desc, rmark
, _geometry , _annox , _annoy
) VALUES ( (SELECT 'INF' || (case length((num + 1)::text)::integer when 1 then '000000' when 2 then '00000' when 3 then '0000' when 4 then '000' when 5 then '00' when 6 then '0' when 7 then '' end) || num + 1 AS val FROM generate_series( (SELECT coalesce(substring(max(mgr_no), 4)::numeric, 0) FROM xeus.asset_infra), (SELECT coalesce(substring(max(mgr_no), 4)::numeric, 0) FROM xeus.asset_infra) ) AS num),
#{orgMgrNo}, #{siteMgrNo}, #{instDat}, #{fclGbnCd}, #{ipAddr},
#{portNum}::numeric,
#{useYn}, #{conId}, #{conPwd}, #{snmpStr}, #{statChkYn}, #{facilityId}, #{facilityNm}, #{locDesc}, #{rmark}
, public.ST_SetSRID(public.ST_MakePoint(#{lng}::numeric, #{lat}::numeric), 5186)
, #{lng}::numeric , #{lat}::numeric
);

mapper.update:
		UPDATE xeus.asset_infra

		SET
            mgr_no = #{mgrNo}


                , org_mgr_no = #{orgMgrNo}



                , site_mgr_no = #{siteMgrNo}



                , inst_dat = #{instDat}



                , fcl_gbn_cd = #{fclGbnCd}



                , ip_addr = #{ipAddr}



                , port_num = #{portNum}::integer



                , use_yn = #{useYn}



				, con_id = #{conId}



				, con_pwd = #{conPwd}



				, snmp_str = #{snmpStr}



                , stat_chk_yn = #{statChkYn}



                , facility_id = #{facilityId}



                , facility_nm = #{facilityNm}



                , facility_clscd = #{facilityClscd}



                , loc_desc = #{locDesc}



                , rmark = #{rmark}



                , _geometry = public.ST_SetSRID(public.ST_MakePoint(#{lng}::numeric, #{lat}::numeric), 5186)
                , _annox = #{lng}::numeric
                , _annoy = #{lat}::numeric


		WHERE mgr_no = #{mgrNo}
